# solution.py
"""Team Collaboration Manager.

A self-contained, thread-safe, in-memory backend for managing users,
projects, tasks, messaging, performance metrics and reporting.

Although the originating brief described a "BookVerse" product, the
authoritative contract for this module is ``test_solution.py`` which
exercises a ``TeamCollaborationManager``.  This file implements exactly
that contract using only the Python standard library and ASCII text.

Design highlights
-----------------
* A single re-entrant lock is shared by the manager and every sub-store
  so that all mutations are serialised and globally consistent.
* Identifiers are drawn from one monotonic counter, so ids are unique
  across users, projects, tasks, messages and ratings.
* Every public accessor returns a deep copy of stored state, guaranteeing
  that callers cannot mutate the manager's internal data structures.
"""

import copy
import csv
import io
import json
import threading
from dataclasses import dataclass, field
from datetime import datetime
from enum import Enum
from typing import Callable, Dict, List, Optional


# ---------------------------------------------------------------------------
# Enumerations
# ---------------------------------------------------------------------------
class UserRole(Enum):
    """Role assigned to a user account."""

    MEMBER = "member"
    ADMIN = "admin"


class TaskStatus(Enum):
    """Lifecycle status of a task."""

    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class ReportFormat(Enum):
    """Supported export formats for generated reports."""

    CSV = "csv"
    PDF = "pdf"


class ReportType(Enum):
    """The kind of report produced by the manager."""

    PROJECT_PROGRESS = "project_progress"
    TEAM_PERFORMANCE = "team_performance"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


# ---------------------------------------------------------------------------
# Exception hierarchy
# ---------------------------------------------------------------------------
class TeamCollaborationError(Exception):
    """Base class for all errors raised by the manager."""


class ValidationError(TeamCollaborationError):
    """Raised when input fails validation."""


class NotFoundError(TeamCollaborationError):
    """Raised when a referenced entity does not exist."""


class AuthorizationError(TeamCollaborationError):
    """Raised when an actor is not permitted to perform an operation."""


class DuplicateError(TeamCollaborationError):
    """Raised when a uniqueness constraint would be violated."""


class ConflictError(TeamCollaborationError):
    """Raised when an operation conflicts with existing state."""


# ---------------------------------------------------------------------------
# Entities
# ---------------------------------------------------------------------------
@dataclass
class User:
    """A registered user account."""

    id: int
    username: str
    email: str
    role: UserRole
    created_at: datetime


@dataclass
class Project:
    """A project owned by a user with a fixed schedule window."""

    id: int
    name: str
    description: str
    start_date: datetime
    end_date: datetime
    owner_id: int
    created_at: datetime


@dataclass
class Task:
    """A unit of work belonging to a project."""

    id: int
    project_id: int
    title: str
    status: TaskStatus
    assignee_id: Optional[int]
    deadline: Optional[datetime]
    created_at: datetime
    started_at: Optional[datetime] = None
    completed_at: Optional[datetime] = None


@dataclass
class Attachment:
    """Binary file metadata attached to a message."""

    filename: str
    size: int
    uploaded_by: int
    uploaded_at: datetime


@dataclass
class Message:
    """A message posted against a project or a task."""

    id: int
    author_id: int
    body: str
    project_id: Optional[int]
    task_id: Optional[int]
    parent_id: Optional[int]
    created_at: datetime
    edited_at: Optional[datetime] = None
    attachments: List[Attachment] = field(default_factory=list)


@dataclass
class Rating:
    """Peer feedback for a user, optionally tied to a task."""

    id: int
    rater_id: int
    ratee_id: int
    score: int
    feedback: str
    task_id: Optional[int]
    created_at: datetime


# ---------------------------------------------------------------------------
# Internal stores
#
# Each store holds the *same* shared lock as the manager.  Keeping the data
# in dedicated objects keeps the manager readable while still letting the
# concurrency tests assert that one lock guards every collection.
# ---------------------------------------------------------------------------
class _UserStore:
    def __init__(self, lock):
        self._lock = lock
        self._items: Dict[int, User] = {}
        self._username_to_id: Dict[str, int] = {}
        self._email_to_id: Dict[str, int] = {}


class _ProjectStore:
    def __init__(self, lock):
        self._lock = lock
        self._items: Dict[int, Project] = {}


class _TaskStore:
    def __init__(self, lock):
        self._lock = lock
        self._items: Dict[int, Task] = {}
        self._by_project: Dict[int, List[int]] = {}
        self._by_assignee: Dict[int, set] = {}


class _MessageStore:
    def __init__(self, lock):
        self._lock = lock
        self._items: Dict[int, Message] = {}
        self._by_project: Dict[int, List[int]] = {}
        self._by_task: Dict[int, List[int]] = {}


class _PerformanceStore:
    def __init__(self, lock):
        self._lock = lock
        self._ratings: Dict[int, Rating] = {}
        self._by_ratee: Dict[int, List[int]] = {}


class _ReportStore:
    def __init__(self, lock):
        self._lock = lock


# ---------------------------------------------------------------------------
# Manager
# ---------------------------------------------------------------------------
class TeamCollaborationManager:
    """In-memory facade coordinating every collaboration feature."""

    def __init__(self, now: Optional[Callable[[], datetime]] = None):
        self._now = now if now is not None else datetime.now
        self._lock = threading.RLock()
        self.users = _UserStore(self._lock)
        self.projects = _ProjectStore(self._lock)
        self.tasks = _TaskStore(self._lock)
        self.messages = _MessageStore(self._lock)
        self.performance = _PerformanceStore(self._lock)
        self.reports = _ReportStore(self._lock)
        self._id_counter = 0

    # -- helpers ----------------------------------------------------------
    def _next_id(self) -> int:
        self._id_counter += 1
        return self._id_counter

    @staticmethod
    def _clone(obj):
        return copy.deepcopy(obj)

    def _get_user(self, user_id) -> User:
        user = self.users._items.get(user_id)
        if user is None:
            raise NotFoundError("User {0} not found".format(user_id))
        return user

    def _get_project(self, project_id) -> Project:
        project = self.projects._items.get(project_id)
        if project is None:
            raise NotFoundError("Project {0} not found".format(project_id))
        return project

    def _get_task(self, task_id) -> Task:
        task = self.tasks._items.get(task_id)
        if task is None:
            raise NotFoundError("Task {0} not found".format(task_id))
        return task

    def _get_message(self, message_id) -> Message:
        message = self.messages._items.get(message_id)
        if message is None:
            raise NotFoundError("Message {0} not found".format(message_id))
        return message

    @staticmethod
    def _is_nonempty_str(value) -> bool:
        return isinstance(value, str) and value.strip() != ""

    @staticmethod
    def _avg_time(tasks) -> Optional[float]:
        durations = [
            (t.completed_at - t.started_at).total_seconds()
            for t in tasks
            if t.status == TaskStatus.COMPLETED
            and t.started_at is not None
            and t.completed_at is not None
        ]
        if not durations:
            return None
        return sum(durations) / len(durations)

    # ------------------------------------------------------------------
    # User management
    # ------------------------------------------------------------------
    def register_user(self, username, email, role=UserRole.MEMBER) -> User:
        with self._lock:
            if not self._is_nonempty_str(username):
                raise ValidationError("username is required")
            if not self._is_nonempty_str(email):
                raise ValidationError("email is required")
            if "@" not in email:
                raise ValidationError("email is invalid")
            if not isinstance(role, UserRole):
                raise ValidationError("role is invalid")
            if username in self.users._username_to_id:
                raise DuplicateError("username already exists")
            if email in self.users._email_to_id:
                raise DuplicateError("email already exists")

            user_id = self._next_id()
            user = User(
                id=user_id,
                username=username,
                email=email,
                role=role,
                created_at=self._now(),
            )
            self.users._items[user_id] = user
            self.users._username_to_id[username] = user_id
            self.users._email_to_id[email] = user_id
            return self._clone(user)

    def get_user(self, user_id) -> User:
        with self._lock:
            return self._clone(self._get_user(user_id))

    def list_users(self) -> List[User]:
        with self._lock:
            ordered = sorted(self.users._items.values(), key=lambda u: u.id)
            return [self._clone(u) for u in ordered]

    def update_user(self, user_id, username=None, email=None, role=None) -> User:
        with self._lock:
            user = self._get_user(user_id)

            if username is not None:
                if not self._is_nonempty_str(username):
                    raise ValidationError("username is required")
                existing = self.users._username_to_id.get(username)
                if existing is not None and existing != user_id:
                    raise DuplicateError("username already exists")

            if email is not None:
                if not self._is_nonempty_str(email) or "@" not in email:
                    raise ValidationError("email is invalid")
                existing = self.users._email_to_id.get(email)
                if existing is not None and existing != user_id:
                    raise DuplicateError("email already exists")

            if role is not None and not isinstance(role, UserRole):
                raise ValidationError("role is invalid")

            if username is not None and username != user.username:
                del self.users._username_to_id[user.username]
                self.users._username_to_id[username] = user_id
                user.username = username
            if email is not None and email != user.email:
                del self.users._email_to_id[user.email]
                self.users._email_to_id[email] = user_id
                user.email = email
            if role is not None:
                user.role = role
            return self._clone(user)

    def delete_user(self, user_id) -> None:
        with self._lock:
            user = self._get_user(user_id)

            for project in self.projects._items.values():
                if project.owner_id == user_id:
                    raise ConflictError("user owns a project")

            assigned = self.tasks._by_assignee.get(user_id, set())
            for task_id in assigned:
                task = self.tasks._items[task_id]
                if task.status != TaskStatus.COMPLETED:
                    raise ConflictError("user has an open task")

            del self.users._items[user_id]
            self.users._username_to_id.pop(user.username, None)
            self.users._email_to_id.pop(user.email, None)
            self.tasks._by_assignee.pop(user_id, None)

    # ------------------------------------------------------------------
    # Project management
    # ------------------------------------------------------------------
    def create_project(
        self, name, start_date, end_date, owner_id, description=""
    ) -> Project:
        with self._lock:
            if not self._is_nonempty_str(name):
                raise ValidationError("project name is required")
            if end_date < start_date:
                raise ValidationError("end_date cannot precede start_date")
            self._get_user(owner_id)

            project_id = self._next_id()
            project = Project(
                id=project_id,
                name=name,
                description=description or "",
                start_date=start_date,
                end_date=end_date,
                owner_id=owner_id,
                created_at=self._now(),
            )
            self.projects._items[project_id] = project
            self.tasks._by_project.setdefault(project_id, [])
            self.messages._by_project.setdefault(project_id, [])
            return self._clone(project)

    def get_project(self, project_id) -> Project:
        with self._lock:
            return self._clone(self._get_project(project_id))

    def list_projects(self) -> List[Project]:
        with self._lock:
            ordered = sorted(self.projects._items.values(), key=lambda p: p.id)
            return [self._clone(p) for p in ordered]

    def update_project(
        self,
        project_id,
        name=None,
        description=None,
        start_date=None,
        end_date=None,
    ) -> Project:
        with self._lock:
            project = self._get_project(project_id)

            new_start = project.start_date if start_date is None else start_date
            new_end = project.end_date if end_date is None else end_date

            if name is not None and not self._is_nonempty_str(name):
                raise ValidationError("project name is required")
            if new_end < new_start:
                raise ValidationError("end_date cannot precede start_date")

            if name is not None:
                project.name = name
            if description is not None:
                project.description = description
            if start_date is not None:
                project.start_date = start_date
            if end_date is not None:
                project.end_date = end_date
            return self._clone(project)

    def delete_project(self, project_id) -> None:
        with self._lock:
            self._get_project(project_id)

            for task_id in list(self.tasks._by_project.get(project_id, [])):
                self._remove_task(task_id)
            for message_id in list(self.messages._by_project.get(project_id, [])):
                self._remove_message(message_id)

            self.tasks._by_project.pop(project_id, None)
            self.messages._by_project.pop(project_id, None)
            del self.projects._items[project_id]

    # ------------------------------------------------------------------
    # Task management
    # ------------------------------------------------------------------
    def create_task(
        self, project_id, title, assignee_id=None, deadline=None
    ) -> Task:
        with self._lock:
            project = self._get_project(project_id)
            if not self._is_nonempty_str(title):
                raise ValidationError("task title is required")
            if deadline is not None and deadline < project.start_date:
                raise ValidationError("deadline cannot precede project start")
            if assignee_id is not None:
                self._get_user(assignee_id)

            task_id = self._next_id()
            task = Task(
                id=task_id,
                project_id=project_id,
                title=title,
                status=TaskStatus.NOT_STARTED,
                assignee_id=assignee_id,
                deadline=deadline,
                created_at=self._now(),
            )
            self.tasks._items[task_id] = task
            self.tasks._by_project.setdefault(project_id, []).append(task_id)
            if assignee_id is not None:
                self.tasks._by_assignee.setdefault(assignee_id, set()).add(task_id)
            return self._clone(task)

    def get_task(self, task_id) -> Task:
        with self._lock:
            return self._clone(self._get_task(task_id))

    def list_tasks_by_project(self, project_id) -> List[Task]:
        with self._lock:
            self._get_project(project_id)
            task_ids = self.tasks._by_project.get(project_id, [])
            tasks = [self.tasks._items[i] for i in task_ids]
            tasks.sort(key=lambda t: t.id)
            return [self._clone(t) for t in tasks]

    def list_tasks_by_assignee(self, assignee_id) -> List[Task]:
        with self._lock:
            self._get_user(assignee_id)
            task_ids = self.tasks._by_assignee.get(assignee_id, set())
            tasks = [self.tasks._items[i] for i in task_ids]
            tasks.sort(key=lambda t: t.id)
            return [self._clone(t) for t in tasks]

    def assign_task(self, task_id, assignee_id) -> Task:
        with self._lock:
            task = self._get_task(task_id)
            self._get_user(assignee_id)
            self._set_assignee(task, assignee_id)
            return self._clone(task)

    def reassign_task(self, task_id, new_assignee_id) -> Task:
        with self._lock:
            task = self._get_task(task_id)
            self._get_user(new_assignee_id)
            self._set_assignee(task, new_assignee_id)
            return self._clone(task)

    def unassign_task(self, task_id) -> Task:
        with self._lock:
            task = self._get_task(task_id)
            self._set_assignee(task, None)
            return self._clone(task)

    def set_deadline(self, task_id, deadline) -> Task:
        with self._lock:
            task = self._get_task(task_id)
            if deadline is not None:
                project = self._get_project(task.project_id)
                if deadline < project.start_date:
                    raise ValidationError("deadline cannot precede project start")
            task.deadline = deadline
            return self._clone(task)

    def update_status(self, task_id, status) -> Task:
        with self._lock:
            if not isinstance(status, TaskStatus):
                raise ValidationError("status is invalid")
            task = self._get_task(task_id)
            now = self._now()
            if status == TaskStatus.NOT_STARTED:
                task.started_at = None
                task.completed_at = None
            elif status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now
            task.status = status
            return self._clone(task)

    def _set_assignee(self, task: Task, assignee_id) -> None:
        old = task.assignee_id
        if old == assignee_id:
            return
        if old is not None:
            bucket = self.tasks._by_assignee.get(old)
            if bucket is not None:
                bucket.discard(task.id)
        task.assignee_id = assignee_id
        if assignee_id is not None:
            self.tasks._by_assignee.setdefault(assignee_id, set()).add(task.id)

    def _remove_task(self, task_id) -> None:
        task = self.tasks._items.pop(task_id, None)
        if task is None:
            return
        bucket = self.tasks._by_project.get(task.project_id)
        if bucket is not None and task_id in bucket:
            bucket.remove(task_id)
        if task.assignee_id is not None:
            assignee_bucket = self.tasks._by_assignee.get(task.assignee_id)
            if assignee_bucket is not None:
                assignee_bucket.discard(task_id)
        for message_id in list(self.messages._by_task.get(task_id, [])):
            self._remove_message(message_id)
        self.messages._by_task.pop(task_id, None)

    # ------------------------------------------------------------------
    # Messaging
    # ------------------------------------------------------------------
    def post_message(
        self,
        author_id,
        body,
        project_id=None,
        task_id=None,
        attachments=None,
        parent_id=None,
    ) -> Message:
        with self._lock:
            self._get_user(author_id)

            if (project_id is None) == (task_id is None):
                raise ValidationError(
                    "exactly one of project_id or task_id is required"
                )
            if project_id is not None:
                self._get_project(project_id)
            if task_id is not None:
                self._get_task(task_id)

            raw_attachments = list(attachments) if attachments else []
            has_body = isinstance(body, str) and body.strip() != ""
            if not has_body and not raw_attachments:
                raise ValidationError("message body or attachment is required")

            if parent_id is not None and parent_id not in self.messages._items:
                raise NotFoundError("parent message not found")

            now = self._now()
            attachment_objs = [
                Attachment(
                    filename=filename,
                    size=len(data),
                    uploaded_by=author_id,
                    uploaded_at=now,
                )
                for filename, data in raw_attachments
            ]

            message_id = self._next_id()
            message = Message(
                id=message_id,
                author_id=author_id,
                body=body if isinstance(body, str) else "",
                project_id=project_id,
                task_id=task_id,
                parent_id=parent_id,
                created_at=now,
                edited_at=None,
                attachments=attachment_objs,
            )
            self.messages._items[message_id] = message
            if project_id is not None:
                self.messages._by_project.setdefault(project_id, []).append(message_id)
            if task_id is not None:
                self.messages._by_task.setdefault(task_id, []).append(message_id)
            return self._clone(message)

    def edit_message(self, message_id, editor_id, new_body) -> Message:
        with self._lock:
            message = self._get_message(message_id)
            if message.author_id != editor_id:
                raise AuthorizationError("only the author may edit this message")
            if not self._is_nonempty_str(new_body):
                raise ValidationError("message body is required")
            message.body = new_body
            message.edited_at = self._now()
            return self._clone(message)

    def add_attachment(self, message_id, user_id, filename, data) -> Message:
        with self._lock:
            message = self._get_message(message_id)
            if message.author_id != user_id:
                raise AuthorizationError(
                    "only the author may attach to this message"
                )
            if not self._is_nonempty_str(filename):
                raise ValidationError("filename is required")
            message.attachments.append(
                Attachment(
                    filename=filename,
                    size=len(data),
                    uploaded_by=user_id,
                    uploaded_at=self._now(),
                )
            )
            return self._clone(message)

    def list_messages_by_project(self, project_id) -> List[Message]:
        with self._lock:
            self._get_project(project_id)
            message_ids = self.messages._by_project.get(project_id, [])
            messages = [self.messages._items[i] for i in message_ids]
            messages.sort(key=lambda m: m.id)
            return [self._clone(m) for m in messages]

    def list_messages_by_task(self, task_id) -> List[Message]:
        with self._lock:
            self._get_task(task_id)
            message_ids = self.messages._by_task.get(task_id, [])
            messages = [self.messages._items[i] for i in message_ids]
            messages.sort(key=lambda m: m.id)
            return [self._clone(m) for m in messages]

    def delete_message(self, message_id, user_id) -> None:
        with self._lock:
            message = self._get_message(message_id)
            if message.author_id != user_id:
                raise AuthorizationError(
                    "only the author may delete this message"
                )
            self._remove_message(message_id)

    def _remove_message(self, message_id) -> None:
        message = self.messages._items.pop(message_id, None)
        if message is None:
            return
        if message.project_id is not None:
            bucket = self.messages._by_project.get(message.project_id)
            if bucket is not None and message_id in bucket:
                bucket.remove(message_id)
        if message.task_id is not None:
            bucket = self.messages._by_task.get(message.task_id)
            if bucket is not None and message_id in bucket:
                bucket.remove(message_id)

    # ------------------------------------------------------------------
    # Performance dashboard
    # ------------------------------------------------------------------
    def get_completion_rate(self, user_id) -> float:
        with self._lock:
            self._get_user(user_id)
            task_ids = self.tasks._by_assignee.get(user_id, set())
            total = len(task_ids)
            if total == 0:
                return 0.0
            completed = sum(
                1
                for i in task_ids
                if self.tasks._items[i].status == TaskStatus.COMPLETED
            )
            return completed / total

    def get_average_completion_time(self, user_id) -> Optional[float]:
        with self._lock:
            self._get_user(user_id)
            task_ids = self.tasks._by_assignee.get(user_id, set())
            tasks = [self.tasks._items[i] for i in task_ids]
            return self._avg_time(tasks)

    def submit_rating(
        self, rater_id, ratee_id, score, feedback="", task_id=None
    ) -> Rating:
        with self._lock:
            self._get_user(rater_id)
            self._get_user(ratee_id)
            if rater_id == ratee_id:
                raise ConflictError("a user cannot rate themselves")
            if isinstance(score, bool) or not isinstance(score, int):
                raise ValidationError("score must be an integer from 1 to 5")
            if score < 1 or score > 5:
                raise ValidationError("score must be an integer from 1 to 5")
            if task_id is not None:
                self._get_task(task_id)

            rating_id = self._next_id()
            rating = Rating(
                id=rating_id,
                rater_id=rater_id,
                ratee_id=ratee_id,
                score=score,
                feedback=feedback or "",
                task_id=task_id,
                created_at=self._now(),
            )
            self.performance._ratings[rating_id] = rating
            self.performance._by_ratee.setdefault(ratee_id, []).append(rating_id)
            return self._clone(rating)

    def get_ratings_summary(self, user_id) -> Dict:
        with self._lock:
            self._get_user(user_id)
            rating_ids = self.performance._by_ratee.get(user_id, [])
            ratings = [self.performance._ratings[i] for i in rating_ids]
            ratings.sort(key=lambda r: r.id)
            count = len(ratings)
            average = sum(r.score for r in ratings) / count if count else 0.0
            return {
                "count": count,
                "average": average,
                "ratings": [self._clone(r) for r in ratings],
            }

    def get_user_dashboard(self, user_id) -> Dict:
        with self._lock:
            self._get_user(user_id)
            task_ids = self.tasks._by_assignee.get(user_id, set())
            tasks = [self.tasks._items[i] for i in task_ids]
            total = len(tasks)
            completed = sum(
                1 for t in tasks if t.status == TaskStatus.COMPLETED
            )
            in_progress = sum(
                1 for t in tasks if t.status == TaskStatus.IN_PROGRESS
            )
            not_started = sum(
                1 for t in tasks if t.status == TaskStatus.NOT_STARTED
            )
            rating_ids = self.performance._by_ratee.get(user_id, [])
            rating_count = len(rating_ids)
            rating_average = (
                sum(self.performance._ratings[i].score for i in rating_ids)
                / rating_count
                if rating_count
                else 0.0
            )
            return {
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": completed / total if total else 0.0,
                "average_completion_time": self._avg_time(tasks),
                "rating_count": rating_count,
                "rating_average": rating_average,
            }

    # ------------------------------------------------------------------
    # Reports
    # ------------------------------------------------------------------
    def project_progress_report(self, project_id) -> Dict:
        with self._lock:
            self._get_project(project_id)
            task_ids = self.tasks._by_project.get(project_id, [])
            tasks = [self.tasks._items[i] for i in task_ids]
            total = len(tasks)

            status_counts = {status.value: 0 for status in TaskStatus}
            for task in tasks:
                status_counts[task.status.value] += 1

            completed = status_counts[TaskStatus.COMPLETED.value]
            now = self._now()
            overdue = sum(
                1
                for task in tasks
                if task.deadline is not None
                and task.deadline < now
                and task.status != TaskStatus.COMPLETED
            )

            per_assignee: Dict[int, Dict[str, float]] = {}
            for task in tasks:
                if task.assignee_id is None:
                    continue
                bucket = per_assignee.setdefault(
                    task.assignee_id,
                    {"total": 0, "completed": 0, "completion_rate": 0.0},
                )
                bucket["total"] += 1
                if task.status == TaskStatus.COMPLETED:
                    bucket["completed"] += 1
            for bucket in per_assignee.values():
                bucket["completion_rate"] = (
                    bucket["completed"] / bucket["total"]
                    if bucket["total"]
                    else 0.0
                )

            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "project_id": project_id,
                "total_tasks": total,
                "status_counts": status_counts,
                "completion_rate": completed / total if total else 0.0,
                "overdue_tasks": overdue,
                "per_assignee": per_assignee,
            }

    def team_performance_report(self, project_id=None) -> Dict:
        with self._lock:
            if project_id is not None:
                self._get_project(project_id)
                pool = [
                    self.tasks._items[i]
                    for i in self.tasks._by_project.get(project_id, [])
                ]
            else:
                pool = list(self.tasks._items.values())

            by_user: Dict[int, List[Task]] = {}
            for task in pool:
                if task.assignee_id is None:
                    continue
                by_user.setdefault(task.assignee_id, []).append(task)

            rows = []
            for user_id in sorted(by_user):
                tasks = by_user[user_id]
                total = len(tasks)
                completed = sum(
                    1 for t in tasks if t.status == TaskStatus.COMPLETED
                )
                in_progress = sum(
                    1 for t in tasks if t.status == TaskStatus.IN_PROGRESS
                )
                not_started = sum(
                    1 for t in tasks if t.status == TaskStatus.NOT_STARTED
                )
                user = self.users._items.get(user_id)
                rows.append(
                    {
                        "user_id": user_id,
                        "username": user.username if user else "",
                        "total_tasks": total,
                        "completed_tasks": completed,
                        "in_progress_tasks": in_progress,
                        "not_started_tasks": not_started,
                        "completion_rate": completed / total if total else 0.0,
                        "average_completion_time": self._avg_time(tasks),
                    }
                )

            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "project_id": project_id,
                "rows": rows,
            }

    def individual_performance_report(self, user_id) -> Dict:
        with self._lock:
            self._get_user(user_id)
            task_ids = self.tasks._by_assignee.get(user_id, set())
            tasks = sorted(
                (self.tasks._items[i] for i in task_ids), key=lambda t: t.id
            )
            total = len(tasks)
            completed = sum(
                1 for t in tasks if t.status == TaskStatus.COMPLETED
            )
            task_rows = [
                {
                    "task_id": t.id,
                    "title": t.title,
                    "status": t.status.value,
                    "project_id": t.project_id,
                    "deadline": t.deadline,
                    "started_at": t.started_at,
                    "completed_at": t.completed_at,
                }
                for t in tasks
            ]
            return {
                "report_type": ReportType.INDIVIDUAL_PERFORMANCE.value,
                "user_id": user_id,
                "total_tasks": total,
                "completed_tasks": completed,
                "completion_rate": completed / total if total else 0.0,
                "average_completion_time": self._avg_time(tasks),
                "tasks": task_rows,
            }

    def export_report(self, report, report_format):
        if not isinstance(report_format, ReportFormat):
            raise ValidationError("report_format must be a ReportFormat")
        if not isinstance(report, dict):
            raise ValidationError("report must be a report dictionary")
        if report_format == ReportFormat.CSV:
            return self._report_to_csv(report)
        return self._report_to_pdf(report)

    # -- export helpers ---------------------------------------------------
    @staticmethod
    def _csv_cell(value) -> str:
        if value is None:
            return ""
        if isinstance(value, Enum):
            return value.value
        if isinstance(value, (dict, list)):
            return json.dumps(value, default=str, sort_keys=True)
        return str(value)

    def _report_to_csv(self, report) -> str:
        output = io.StringIO()
        writer = csv.writer(output)
        rows = report.get("rows")
        if isinstance(rows, list) and rows and all(
            isinstance(row, dict) for row in rows
        ):
            headers: List[str] = []
            for row in rows:
                for key in row.keys():
                    if key not in headers:
                        headers.append(key)
            writer.writerow(headers)
            for row in rows:
                writer.writerow([self._csv_cell(row.get(h)) for h in headers])
        else:
            writer.writerow(["field", "value"])
            for key, value in report.items():
                writer.writerow([key, self._csv_cell(value)])
        return output.getvalue()

    def _report_to_pdf(self, report) -> bytes:
        lines = ["Report: {0}".format(report.get("report_type", "report"))]
        for key, value in report.items():
            if key == "rows" and isinstance(value, list):
                lines.append("rows: {0} entries".format(len(value)))
            elif key == "tasks" and isinstance(value, list):
                lines.append("tasks: {0} entries".format(len(value)))
            else:
                lines.append("{0}: {1}".format(key, self._csv_cell(value)))
        return self._build_pdf(lines)

    @staticmethod
    def _pdf_escape(text) -> str:
        text = str(text)
        text = text.replace("\\", "\\\\").replace("(", "\\(").replace(")", "\\)")
        return "".join(ch for ch in text if 32 <= ord(ch) < 127)

    def _build_pdf(self, lines) -> bytes:
        operations = ["BT", "/F1 12 Tf", "72 720 Td", "14 TL"]
        for index, line in enumerate(lines):
            if index > 0:
                operations.append("T*")
            operations.append("({0}) Tj".format(self._pdf_escape(line)))
        operations.append("ET")
        content = "\n".join(operations).encode("latin-1", "replace")

        objects = [
            b"<< /Type /Catalog /Pages 2 0 R >>",
            b"<< /Type /Pages /Kids [3 0 R] /Count 1 >>",
            (
                b"<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] "
                b"/Resources << /Font << /F1 5 0 R >> >> /Contents 4 0 R >>"
            ),
            b"<< /Length "
            + str(len(content)).encode("ascii")
            + b" >>\nstream\n"
            + content
            + b"\nendstream",
            b"<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>",
        ]

        pdf = bytearray(b"%PDF-1.4\n")
        offsets = []
        for number, body in enumerate(objects, start=1):
            offsets.append(len(pdf))
            pdf += str(number).encode("ascii") + b" 0 obj\n" + body + b"\nendobj\n"

        xref_position = len(pdf)
        size = len(objects) + 1
        pdf += b"xref\n"
        pdf += b"0 " + str(size).encode("ascii") + b"\n"
        pdf += b"0000000000 65535 f \n"
        for offset in offsets:
            pdf += "{0:010d} 00000 n \n".format(offset).encode("ascii")
        pdf += b"trailer\n"
        pdf += b"<< /Size " + str(size).encode("ascii") + b" /Root 1 0 R >>\n"
        pdf += b"startxref\n"
        pdf += str(xref_position).encode("ascii") + b"\n"
        pdf += b"%%EOF"
        return bytes(pdf)


